+pub struct MetaLearningHealth {
+    pub regret: RegretSummary,
+    pub pareto_size: usize,
+    pub pareto_hypervolume: f32,
+    pub consecutive_plateaus: u32,
+    pub total_plateaus: u32,
+    pub curiosity_total_visits: u64,
