+    /// True if regret growth is sublinear (system is learning).
+    pub is_learning: bool,
+    /// True if Pareto front has diverse solutions.
+    pub is_diverse: bool,
+    /// True if curiosity is actively exploring.
+    pub is_exploring: bool,
+}
