+/// Serialize a `CostCurve` into an RVF COST_CURVE segment.
+pub fn cost_curve_to_segment(curve: &CostCurve, segment_id: u64) -> Vec<u8> {
+    let payload = serde_json::to_vec(curve).expect("CostCurve serialization cannot fail");
