+        assert_eq!(p.beta, 1.0);
+        assert!(p.mean() > 0.5);
+    }
+
+    #[test]
+    fn test_beta_params_sample_in_range() {
+        let p = BetaParams::from_observations(10.0, 5.0);
+        let mut rng = rand::thread_rng();
+        for _ in 0..100 {
+            let s = p.sample(&mut rng);
+            assert!(s >= 0.0 && s <= 1.0, "Sample {} out of [0,1]", s);
+        }
+    }
