+#[derive(Debug, Clone, serde::Serialize, serde::Deserialize)]
+pub struct BenchConfig {
+    pub model_commit: String,
+    pub weights_hash: String,
+    pub lambda: f32,
+    pub tau: usize,
+    pub eps: f32,
+    pub compiler_flags: String,
